class ResBlockDown(nn.Module):
    """Residual block for WGAN-GP critic: GroupNorm, AvgPool downsampling."""
    def __init__(self, in_ch, out_ch, num_groups=32):
        super().__init__()
        self.residual = nn.Sequential(
            nn.GroupNorm(min(num_groups, in_ch), in_ch),
            nn.LeakyReLU(0.2),
            nn.Conv2d(in_ch, out_ch, 3, 1, 1),
            nn.GroupNorm(min(num_groups, out_ch), out_ch),
            nn.LeakyReLU(0.2),
            nn.Conv2d(out_ch, out_ch, 3, 1, 1),
            nn.AvgPool2d(2),
        )
        # Shortcut: match channels + pool
        self.skip = nn.Sequential(
            nn.Conv2d(in_ch, out_ch, 1, bias=False),
            nn.AvgPool2d(2),
        )

    def forward(self, x):
        return self.residual(x) + self.skip(x)


class ResNetCritic(nn.Module):
    def __init__(self, nc=3, ndf=128):
        super().__init__()
        self.main = nn.Sequential(
            nn.Conv2d(nc, ndf, 3, 1, 1),
            ResBlockDown(ndf, ndf * 2),
            ResBlockDown(ndf * 2, ndf * 4),
            ResBlockDown(ndf * 4, ndf * 8),
            nn.AdaptiveAvgPool2d(1),
        )
        self.head = nn.Linear(ndf * 8, 1)

    def forward(self, x):
        h = self.main(x).view(x.size(0), -1)
        return self.head(h).view(-1)
